if __name__ == "__main__":
    graph = {'A': ['B', 'C'], 'B': ['A', 'D'], 'C': ['A', 'D'], 'D': ['B', 'C']}
    print("BFS from A:", bfs(graph, 'A'))

    grid = [['1','1','0'],['1','0','0'],['0','0','1']]
    print("Islands:", num_islands(grid))

    print("Can Finish Courses:", can_finish(2, [[1, 0]]))

